questions = [
  {"id":1,"domain":1,"subdomain":"1.1","objective":"Compare and contrast various types of security controls","stem":"Which category of security control is a security guard patrolling a data center?","options":{"A":"Technical","B":"Managerial","C":"Operational","D":"Physical"},"correct_answer":"D","difficulty":2,"explanations":{"correct":"Physical controls involve tangible, real-world mechanisms that protect assets — security guards, fences, locks, and cameras all fall into this category.","A":"Technical controls use technology to protect assets (firewalls, encryption, access control lists).","B":"Managerial controls are administrative in nature, such as policies, risk assessments, and security training programs.","C":"Operational controls involve day-to-day procedures carried out by people, but a patrol is specifically a physical control.","D":"Correct. A security guard physically monitoring a location is the textbook example of a physical control."}},
  {"id":2,"domain":1,"subdomain":"1.1","objective":"Compare and contrast various types of security controls","stem":"A company requires all employees to complete annual security awareness training. This is BEST classified as which type of control?","options":{"A":"Technical — preventive","B":"Managerial — administrative","C":"Operational — detective","D":"Physical — deterrent"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Security awareness training is a managerial/administrative control; it addresses human behavior through policy and education rather than technology or physical means.","A":"Technical controls use technology, not training programs.","B":"Correct. Training is an administrative (managerial) control that manages risk through human behavior guidance.","C":"Operational controls involve procedures, but detective controls identify incidents after they occur — training is preventive and administrative.","D":"Physical controls involve tangible objects or environmental protections, not training."}},
  {"id":3,"domain":1,"subdomain":"1.1","objective":"Compare and contrast various types of security controls","stem":"An organization installs a motion-activated camera that only records when movement is detected. What control TYPE does this BEST represent?","options":{"A":"Deterrent","B":"Preventive","C":"Detective","D":"Corrective"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Detective controls identify and record security events after they begin occurring. A camera that captures motion events is detecting incidents.","A":"Deterrent controls discourage attacks (signs warning of cameras deter, but the camera itself that records is detective).","B":"Preventive controls stop incidents from occurring; recording a motion event does not prevent it.","C":"Correct. Recording motion events detects incidents in progress or after the fact.","D":"Corrective controls restore systems to normal after an incident — not the function of a recording camera."}},
  {"id":4,"domain":1,"subdomain":"1.1","objective":"Compare and contrast various types of security controls","stem":"After a primary firewall fails, a second firewall automatically takes over. This is an example of which control type?","options":{"A":"Compensating","B":"Corrective","C":"Directive","D":"Deterrent"},"correct_answer":"A","difficulty":3,"explanations":{"correct":"Compensating controls are alternatives implemented when the primary control cannot be used; a failover firewall compensates for the primary's failure.","A":"Correct. The backup firewall compensates for the failed primary control.","B":"Corrective controls restore systems after an incident; a failover firewall is proactively maintaining security, not correcting damage.","C":"Directive controls specify required actions (policies, procedures); not applicable here.","D":"Deterrent controls discourage attacks; failover appliances are operational redundancy, not deterrence."}},
  {"id":5,"domain":1,"subdomain":"1.1","objective":"Compare and contrast various types of security controls","stem":"A 'Warning: This system is monitored' banner displayed at login is BEST classified as which control type?","options":{"A":"Detective","B":"Corrective","C":"Deterrent","D":"Compensating"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Deterrent controls discourage attackers from attempting unauthorized access. A warning banner signals that the system is monitored, discouraging malicious activity.","A":"Detective controls identify events that have occurred; a banner before login does not detect anything.","B":"Corrective controls repair damage after an incident.","C":"Correct. Warning banners deter potential attackers by informing them of monitoring.","D":"Compensating controls serve as alternatives when primary controls fail."}},
  {"id":6,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"Which component of the CIA triad is MOST at risk when a server experiences unplanned downtime?","options":{"A":"Confidentiality","B":"Integrity","C":"Availability","D":"Accountability"},"correct_answer":"C","difficulty":1,"explanations":{"correct":"Availability ensures that authorized users can access systems and data when needed. Unplanned downtime directly prevents access, violating availability.","A":"Confidentiality prevents unauthorized disclosure of data; downtime does not inherently expose data.","B":"Integrity ensures data is accurate and unaltered; downtime doesn't modify data.","C":"Correct. Downtime means the service is unavailable, which is a direct availability failure.","D":"Accountability (non-repudiation) tracks user actions; it is not a CIA triad component."}},
  {"id":7,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"An attacker modifies a financial report stored on a file server without authorization. Which CIA triad principle is violated?","options":{"A":"Confidentiality","B":"Integrity","C":"Availability","D":"Authentication"},"correct_answer":"B","difficulty":1,"explanations":{"correct":"Integrity ensures data remains accurate and unmodified. Unauthorized modification of a file directly violates integrity.","A":"Confidentiality would be violated if the attacker viewed the report without authorization, but modification is an integrity issue.","B":"Correct. Unauthorized modification is a classic integrity violation.","C":"Availability concerns access to systems and services, not data modification.","D":"Authentication is the process of verifying identity, not a CIA triad property."}},
  {"id":8,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"Which AAA component is responsible for tracking what resources a user accessed and for how long?","options":{"A":"Authentication","B":"Authorization","C":"Accounting","D":"Auditing"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Accounting (also called auditing in some frameworks) tracks user activities including resource access, session duration, and data transferred.","A":"Authentication verifies the identity of a user before granting access.","B":"Authorization determines what an authenticated user is permitted to do.","C":"Correct. Accounting logs user activity for billing, auditing, and security review purposes.","D":"Auditing is related to accounting but is not the AAA 'A' that tracks resource use — accounting is the formal AAA term."}},
  {"id":9,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"An organization adopts a 'never trust, always verify' security model that treats every access request as potentially hostile regardless of network location. This is BEST described as:","options":{"A":"Defense in depth","B":"Least privilege","C":"Zero trust","D":"Need-to-know"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Zero trust is defined by the principle of 'never trust, always verify' — no implicit trust is granted based on network location or prior authentication.","A":"Defense in depth layers multiple security controls; it does not specifically address implicit trust.","B":"Least privilege restricts access to the minimum necessary; related but not the same as zero trust.","C":"Correct. Zero trust explicitly rejects implicit trust and requires continuous verification.","D":"Need-to-know restricts information access based on job requirements, not the same comprehensive model."}},
  {"id":10,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"A security team deploys a system that intentionally appears vulnerable to attract and monitor attackers. This technology is called a:","options":{"A":"Honeynet","B":"Honeypot","C":"Honeyfile","D":"Sandbox"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"A honeypot is a single decoy system designed to attract attackers and study their techniques.","A":"A honeynet is a network of honeypots, not a single system.","B":"Correct. A honeypot is a single decoy system used to detect and study attacks.","C":"A honeyfile is a decoy file placed to detect unauthorized access, not an entire system.","D":"A sandbox isolates code for safe execution/testing, not an attacker lure."}},
  {"id":11,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"Which principle ensures that a user who sent a message cannot later deny having sent it?","options":{"A":"Integrity","B":"Confidentiality","C":"Non-repudiation","D":"Authentication"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Non-repudiation prevents a party from denying an action they performed. Digital signatures implement non-repudiation by cryptographically binding a message to its sender.","A":"Integrity ensures data isn't altered, but doesn't prevent a sender from denying authorship.","B":"Confidentiality protects data from unauthorized disclosure.","C":"Correct. Non-repudiation means a sender cannot deny sending a message they cryptographically signed.","D":"Authentication verifies identity at access time, but cannot prevent later denial."}},
  {"id":12,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"A gap analysis in security is BEST used to:","options":{"A":"Detect active intrusions in real time","B":"Identify differences between current and desired security posture","C":"Monitor user behavior for anomalies","D":"Enforce least privilege access controls"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"A gap analysis compares the current state of security controls against a target state (such as a framework like NIST CSF), identifying areas that need improvement.","A":"Real-time intrusion detection is handled by IDS/IPS and SIEM, not gap analysis.","B":"Correct. Gap analysis identifies the delta between where security is now and where it should be.","C":"User behavior monitoring is handled by UEBA tools.","D":"Least privilege enforcement is a specific access control action, not the purpose of gap analysis."}},
  {"id":13,"domain":1,"subdomain":"1.3","objective":"Explain the importance of change management processes","stem":"Before making changes to a production system, an organization requires that changes be reviewed and approved by a committee. This committee is MOST commonly called a:","options":{"A":"Security Operations Center (SOC)","B":"Change Advisory Board (CAB)","C":"Risk Management Committee","D":"Incident Response Team (IRT)"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"The Change Advisory Board reviews and approves proposed changes to production systems to minimize risk and ensure proper authorization.","A":"The SOC monitors for security events; it doesn't govern change management approvals.","B":"Correct. The CAB is the standard change management governance body.","C":"Risk Management Committees address organizational risk strategy, not day-to-day change approvals.","D":"The IRT responds to security incidents, not production changes."}},
  {"id":14,"domain":1,"subdomain":"1.3","objective":"Explain the importance of change management processes","stem":"A technician makes an emergency change to a production server without prior approval. Later, the server fails and the cause cannot be determined. Which change management principle was violated?","options":{"A":"Least privilege","B":"Version control","C":"Documentation and approval","D":"Separation of duties"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Change management requires all changes be documented and approved before implementation. Without documentation, troubleshooting is nearly impossible and accountability is lost.","A":"Least privilege relates to access rights, not change management.","B":"Version control tracks code changes; while related, it's not the primary violated principle here.","C":"Correct. The fundamental violations are lack of prior approval and documentation.","D":"Separation of duties requires that no single person controls an entire critical process; while the technician may have bypassed controls, the primary issue is documentation and approval."}},
  {"id":15,"domain":1,"subdomain":"1.3","objective":"Explain the importance of change management processes","stem":"Which change management concept involves having a documented procedure to reverse a change if it causes problems?","options":{"A":"Change freeze","B":"Rollback plan","C":"Impact analysis","D":"Maintenance window"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"A rollback plan (or backout plan) defines steps to revert a change if it causes unintended consequences, restoring the prior state.","A":"A change freeze temporarily halts all non-emergency changes, often before major events.","B":"Correct. A rollback plan ensures changes can be reversed if they fail.","C":"Impact analysis assesses the potential effects of a change before it is made.","D":"A maintenance window is the scheduled time during which changes are implemented."}},
  {"id":16,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"Which encryption type uses the same key for both encryption and decryption?","options":{"A":"Asymmetric","B":"Symmetric","C":"Hashing","D":"Elliptic curve"},"correct_answer":"B","difficulty":1,"explanations":{"correct":"Symmetric encryption uses a single shared secret key for both encrypting and decrypting data. It is fast but requires secure key exchange.","A":"Asymmetric encryption uses a public/private key pair — different keys for encryption and decryption.","B":"Correct. Symmetric encryption uses the same key for both operations.","C":"Hashing produces a one-way digest, not encryption — data cannot be decrypted from a hash.","D":"Elliptic curve cryptography is an asymmetric algorithm type, not a separate encryption category."}},
  {"id":17,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"A user encrypts a message using the recipient's public key. Which key does the recipient use to decrypt it?","options":{"A":"The sender's public key","B":"The sender's private key","C":"The recipient's public key","D":"The recipient's private key"},"correct_answer":"D","difficulty":2,"explanations":{"correct":"In asymmetric encryption, anything encrypted with a public key can only be decrypted with the corresponding private key. The recipient's private key decrypts messages encrypted with their public key.","A":"The sender's public key is unrelated to decrypting a message sent to the recipient.","B":"The sender's private key is used to sign messages, not to decrypt messages sent to the recipient.","C":"You cannot decrypt with the public key that was used to encrypt — only the corresponding private key works.","D":"Correct. The recipient's private key decrypts what was encrypted with their public key."}},
  {"id":18,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"Which hashing algorithm produces a 256-bit digest and is currently recommended for secure use?","options":{"A":"MD5","B":"SHA-1","C":"SHA-256","D":"DES"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"SHA-256 is part of the SHA-2 family and produces a 256-bit hash. It is currently considered secure and widely used for integrity verification and digital signatures.","A":"MD5 produces a 128-bit hash and is cryptographically broken — not recommended for security purposes.","B":"SHA-1 produces a 160-bit hash and is deprecated due to known collision vulnerabilities.","C":"Correct. SHA-256 produces a 256-bit digest and is recommended for current use.","D":"DES is a symmetric encryption algorithm, not a hashing algorithm."}},
  {"id":19,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"A company uses PKI certificates to secure its website. Which entity signs and issues these certificates?","options":{"A":"Registration Authority (RA)","B":"Certificate Revocation List (CRL)","C":"Certificate Authority (CA)","D":"Online Certificate Status Protocol (OCSP)"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"A Certificate Authority (CA) is the trusted entity in PKI that signs and issues digital certificates, verifying the binding between a public key and an identity.","A":"The Registration Authority (RA) handles certificate enrollment and identity verification but delegates signing to the CA.","B":"The CRL is a list of revoked certificates, not an issuing entity.","C":"Correct. The CA signs and issues certificates.","D":"OCSP is a protocol for checking certificate revocation status, not an issuing entity."}},
  {"id":20,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"Which cryptographic algorithm is considered MOST resistant to quantum computing attacks?","options":{"A":"RSA-2048","B":"AES-128","C":"AES-256","D":"SHA-1"},"correct_answer":"C","difficulty":4,"explanations":{"correct":"AES-256 requires approximately 2^128 operations for a quantum computer using Grover's algorithm, making it the most quantum-resistant of the listed options. NIST recommends 256-bit symmetric keys for post-quantum security.","A":"RSA-2048 is vulnerable to Shor's algorithm on a quantum computer and would be broken.","B":"AES-128 is reduced to roughly 64-bit effective security by Grover's algorithm, below the recommended threshold.","C":"Correct. AES-256 retains ~128 bits of quantum security, meeting post-quantum recommendations.","D":"SHA-1 is deprecated and vulnerable to classical attacks, making it the worst choice."}},
  {"id":21,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"A digital signature provides which TWO security properties? (Choose the BEST answer)","options":{"A":"Confidentiality and availability","B":"Integrity and non-repudiation","C":"Authentication and availability","D":"Confidentiality and integrity"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Digital signatures verify that data has not been altered (integrity) and prove the signer's identity so they cannot deny signing (non-repudiation).","A":"Digital signatures do not provide confidentiality (they don't encrypt data) or availability.","B":"Correct. Digital signatures provide integrity and non-repudiation.","C":"Digital signatures provide authentication of the sender, but not availability.","D":"Digital signatures do not encrypt data, so they don't provide confidentiality."}},
  {"id":22,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"Which term describes hiding secret data within an ordinary, non-secret file such as an image?","options":{"A":"Encryption","B":"Obfuscation","C":"Steganography","D":"Tokenization"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Steganography hides the existence of a message by embedding it within a carrier file (image, audio, video) without visibly altering the carrier.","A":"Encryption scrambles data to make it unreadable but does not hide that encrypted data exists.","B":"Obfuscation makes data harder to understand but does not hide it inside another file.","C":"Correct. Steganography conceals secret data within an innocent carrier file.","D":"Tokenization replaces sensitive data with a non-sensitive placeholder token."}},
  {"id":23,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"Which PKI component maintains a list of certificates that have been revoked before their expiration date?","options":{"A":"OCSP","B":"CSR","C":"CRL","D":"CA"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"The Certificate Revocation List (CRL) is a list published by the CA containing the serial numbers of certificates that have been revoked and should no longer be trusted.","A":"OCSP (Online Certificate Status Protocol) is an alternative to CRL that allows real-time revocation checking but is not the list itself.","B":"A CSR (Certificate Signing Request) is submitted by an entity requesting a certificate.","C":"Correct. The CRL is the list of revoked certificates maintained by the CA.","D":"The CA issues and signs certificates; it publishes the CRL but is not the CRL itself."}},
  {"id":24,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"A company replaces credit card numbers in its database with random tokens that can be mapped back to the real number only via a secure vault. This is called:","options":{"A":"Encryption","B":"Hashing","C":"Masking","D":"Tokenization"},"correct_answer":"D","difficulty":2,"explanations":{"correct":"Tokenization replaces sensitive data (like credit card numbers) with non-sensitive tokens. The original data is stored securely and can be retrieved via a token vault.","A":"Encryption transforms data into ciphertext that can be decrypted with a key — different from token substitution.","B":"Hashing is a one-way process and cannot be reversed to retrieve the original value.","C":"Masking obscures data by replacing characters (e.g., showing only last 4 digits) — unlike tokenization, no vault is needed.","D":"Correct. Tokenization substitutes real data with tokens that map back to originals only via a vault."}},
  {"id":25,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"Which type of certificate is used to secure multiple subdomains under a single domain (e.g., *.example.com)?","options":{"A":"Root certificate","B":"Self-signed certificate","C":"Wildcard certificate","D":"Extended validation certificate"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"A wildcard certificate uses an asterisk (*) as a subdomain placeholder, securing all first-level subdomains under the specified domain with a single certificate.","A":"A root certificate is the top-level CA certificate that anchors trust chains.","B":"A self-signed certificate is issued by the entity itself, not a trusted CA — used in testing environments.","C":"Correct. Wildcard certificates cover all subdomains matching the *.domain.com pattern.","D":"Extended Validation (EV) certificates require rigorous identity verification by the CA; they don't cover multiple subdomains by default."}},
  {"id":26,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"Which access control model assigns permissions based on labels like TOP SECRET and SECRET and is enforced by the system rather than the data owner?","options":{"A":"Discretionary Access Control (DAC)","B":"Role-Based Access Control (RBAC)","C":"Mandatory Access Control (MAC)","D":"Attribute-Based Access Control (ABAC)"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"MAC uses security labels (classifications) assigned by the system. Access decisions are made by the system based on label comparisons — users cannot change these labels.","A":"DAC allows the data owner to set permissions at their discretion; the owner controls access.","B":"RBAC assigns permissions based on job roles, not security labels.","C":"Correct. MAC enforces access via system-assigned labels and is used in high-security environments like military systems.","D":"ABAC makes access decisions based on multiple attributes (user, resource, environment), not just labels."}},
  {"id":27,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"A company grants access to files based on employees' job titles (e.g., Manager, Engineer, HR). This is an example of:","options":{"A":"Mandatory Access Control","B":"Role-Based Access Control","C":"Discretionary Access Control","D":"Attribute-Based Access Control"},"correct_answer":"B","difficulty":1,"explanations":{"correct":"Role-Based Access Control (RBAC) assigns permissions based on defined roles within an organization. Access is determined by the role (job title) rather than individual user identity.","A":"MAC uses security labels enforced by the system, not job titles.","B":"Correct. RBAC maps access rights to roles like Manager, Engineer, or HR.","C":"DAC allows resource owners to set permissions for individual users.","D":"ABAC uses multiple dynamic attributes to make access decisions."}},
  {"id":28,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"Which principle states that no single individual should have the ability to perform all steps of a critical process alone?","options":{"A":"Least privilege","B":"Need-to-know","C":"Separation of duties","D":"Job rotation"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Separation of duties requires that critical tasks be divided among multiple people to prevent fraud, errors, and abuse. No single person should control an entire sensitive process.","A":"Least privilege limits access to the minimum required for a job function, not about distributing critical tasks.","B":"Need-to-know restricts information access to only those who require it for their role.","C":"Correct. Separation of duties splits critical functions across multiple people to prevent single-person abuse.","D":"Job rotation moves employees between roles periodically, which helps detect fraud but is not the same principle."}},
  {"id":29,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"AES-256 is classified as which type of encryption algorithm?","options":{"A":"Asymmetric","B":"Hashing","C":"Symmetric","D":"Elliptic curve"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"AES (Advanced Encryption Standard) is a symmetric block cipher. The same key is used to both encrypt and decrypt data.","A":"Asymmetric algorithms use key pairs (public/private), such as RSA or ECC.","B":"Hashing produces one-way digests; AES is reversible with the correct key.","C":"Correct. AES is a symmetric algorithm using the same key for encryption and decryption.","D":"Elliptic curve cryptography is an asymmetric approach; AES is symmetric."}},
  {"id":30,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"A certificate has been compromised. The administrator checks validity using a real-time query rather than downloading a full list. Which protocol is being used?","options":{"A":"CRL","B":"OCSP","C":"LDAP","D":"RADIUS"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"OCSP (Online Certificate Status Protocol) allows clients to query a certificate's revocation status in real time, without downloading the full CRL.","A":"CRL (Certificate Revocation List) is a downloadable list, not a real-time query protocol.","B":"Correct. OCSP provides real-time certificate status checks.","C":"LDAP is a directory service protocol, not a certificate revocation protocol.","D":"RADIUS is an authentication protocol for network access, not certificate validation."}},
  {"id":31,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"Which algorithm is commonly used for key exchange and provides forward secrecy?","options":{"A":"RSA","B":"AES","C":"ECDHE","D":"SHA-256"},"correct_answer":"C","difficulty":4,"explanations":{"correct":"ECDHE (Elliptic Curve Diffie-Hellman Ephemeral) provides forward secrecy by generating a new key pair for each session, so compromising a long-term key doesn't expose past sessions.","A":"RSA can perform key exchange but does not provide forward secrecy when used without ephemeral keys.","B":"AES is a symmetric encryption algorithm used after keys have been exchanged.","C":"Correct. ECDHE uses ephemeral keys and provides perfect forward secrecy.","D":"SHA-256 is a hashing algorithm, not used for key exchange."}},
  {"id":32,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"Which deception technology creates an entire fake network segment with multiple decoy systems?","options":{"A":"Honeypot","B":"Honeyfile","C":"Honeynet","D":"Sandnet"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"A honeynet is a controlled network of honeypots designed to attract attackers. It simulates multiple systems and services for more comprehensive threat intelligence gathering.","A":"A honeypot is a single decoy system, not a full network.","B":"A honeyfile is a decoy file used to detect unauthorized access to data.","C":"Correct. A honeynet is a network of multiple honeypot systems.","D":"Sandnet is not a recognized deception technology term."}},
  {"id":33,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"Which encryption mode is considered INSECURE because it encrypts identical plaintext blocks into identical ciphertext blocks?","options":{"A":"CBC","B":"ECB","C":"CTR","D":"GCM"},"correct_answer":"B","difficulty":4,"explanations":{"correct":"Electronic Codebook (ECB) mode encrypts each block independently with the same key, meaning identical plaintext blocks produce identical ciphertext blocks — patterns are preserved, revealing information.","A":"CBC (Cipher Block Chaining) XORs each block with the previous ciphertext, preventing identical blocks from producing identical output.","B":"Correct. ECB is insecure because patterns in plaintext are visible in ciphertext.","C":"CTR (Counter) mode uses a counter value with each block, producing unique ciphertext even for identical plaintext.","D":"GCM (Galois/Counter Mode) provides authenticated encryption and is considered secure."}},
  {"id":34,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"Which term describes adding random data to a password before hashing it to prevent rainbow table attacks?","options":{"A":"Padding","B":"Salting","C":"Key stretching","D":"Initialization vector"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Salting adds a unique random value (salt) to each password before hashing, ensuring that even identical passwords produce different hashes and making precomputed rainbow tables ineffective.","A":"Padding fills data to meet block size requirements in block ciphers, not related to password security.","B":"Correct. Salting adds random data to passwords before hashing to defeat rainbow table attacks.","C":"Key stretching (e.g., bcrypt, PBKDF2) makes hashing computationally expensive to slow brute-force attacks — different from salting but often used together.","D":"An initialization vector (IV) is used in encryption modes like CBC to ensure that identical plaintext produces different ciphertext."}},
  {"id":35,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"Which cryptographic concept uses a distributed ledger to ensure immutability of transaction records?","options":{"A":"Quantum cryptography","B":"Steganography","C":"Blockchain","D":"Homomorphic encryption"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Blockchain maintains a distributed, append-only ledger where each block contains the hash of the prior block. This cryptographic chaining makes records tamper-evident and immutable.","A":"Quantum cryptography uses quantum mechanics for secure key distribution (QKD), not distributed ledgers.","B":"Steganography hides data within other files; it is not a ledger technology.","C":"Correct. Blockchain uses cryptographic hashing and distributed consensus to create an immutable transaction ledger.","D":"Homomorphic encryption allows computations on encrypted data without decrypting it — not a ledger technology."}},
  {"id":36,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"A user is only given access to the specific data and systems needed to perform their job — nothing more. This implements which security principle?","options":{"A":"Separation of duties","B":"Least privilege","C":"Need-to-know","D":"Mandatory access control"},"correct_answer":"B","difficulty":1,"explanations":{"correct":"The principle of least privilege grants users only the minimum access rights necessary to perform their job functions, reducing the attack surface.","A":"Separation of duties distributes critical tasks across multiple people, not about access minimization.","B":"Correct. Least privilege limits access to the minimum required for job functions.","C":"Need-to-know is a related but narrower concept typically applied to classified information.","D":"MAC is an access control model enforced by the system; least privilege is a principle that can apply to any model."}},
  {"id":37,"domain":1,"subdomain":"1.3","objective":"Explain the importance of change management processes","stem":"Which change management process involves evaluating the potential effects of a change on other systems and services?","options":{"A":"Rollback planning","B":"Impact analysis","C":"Change freeze","D":"Version control"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Impact analysis assesses the potential consequences of a proposed change on dependent systems, services, and business processes before the change is approved.","A":"Rollback planning prepares for reverting a change if it fails.","B":"Correct. Impact analysis evaluates the potential effects before a change is made.","C":"A change freeze temporarily stops all non-emergency changes.","D":"Version control tracks changes to code and configurations over time."}},
  {"id":38,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"A self-signed certificate differs from a CA-signed certificate because:","options":{"A":"Self-signed certificates use stronger encryption","B":"Self-signed certificates are not trusted by default by external clients","C":"Self-signed certificates expire faster","D":"Self-signed certificates cannot use asymmetric keys"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"Self-signed certificates are signed by the entity that created them, not a trusted CA. Browsers and clients do not trust them by default and will display warnings.","A":"The signing entity has no effect on the encryption strength used by the certificate.","B":"Correct. Without a trusted CA's signature, clients will not automatically trust a self-signed certificate.","C":"Certificate expiration is set by the issuer, not determined by whether it is self-signed.","D":"Self-signed certificates can and do use asymmetric keys — the key type is independent of who signed the certificate."}},
  {"id":39,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"Which of the following BEST describes Perfect Forward Secrecy (PFS)?","options":{"A":"Encrypting data twice with two different algorithms","B":"Using a hardware security module to store private keys","C":"Generating unique session keys for each connection so past sessions remain secure if long-term keys are compromised","D":"Requiring multi-factor authentication before key exchange"},"correct_answer":"C","difficulty":4,"explanations":{"correct":"PFS ensures that compromise of a server's long-term private key does not expose previously recorded encrypted sessions, because each session uses an independently generated ephemeral key.","A":"Using two algorithms (double encryption) is not PFS.","B":"HSMs protect key storage but don't provide forward secrecy on their own.","C":"Correct. PFS uses ephemeral session keys so past traffic cannot be decrypted if the long-term key is later compromised.","D":"MFA is an authentication mechanism, not a key exchange property."}},
  {"id":40,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"A company stores employee badges' access codes in a format where only the last 4 digits are visible in reports. This is an example of:","options":{"A":"Tokenization","B":"Encryption","C":"Data masking","D":"Hashing"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Data masking replaces part of sensitive data with obfuscated characters (e.g., showing only the last 4 digits), protecting the sensitive portion while retaining usability.","A":"Tokenization replaces the entire value with a non-sensitive token that maps back to the original in a vault.","B":"Encryption transforms the full value into ciphertext; partial visibility of digits is not encryption.","C":"Correct. Masking partially conceals sensitive data, like displaying only the last 4 digits of a badge code.","D":"Hashing produces a fixed-length digest of the entire value and cannot be partially reversed."}},
  {"id":41,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"Which protocol provides a framework for negotiating encryption algorithms and exchanging keys at the beginning of a TLS session?","options":{"A":"TLS Record Protocol","B":"TLS Handshake Protocol","C":"DTLS","D":"IPsec IKE"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"The TLS Handshake Protocol negotiates cipher suites, authenticates parties, and establishes session keys before data exchange begins.","A":"The TLS Record Protocol handles the actual encryption and transport of application data after the handshake.","B":"Correct. The TLS Handshake Protocol establishes the secure session parameters.","C":"DTLS is TLS adapted for datagram (UDP) transport, not the handshake component itself.","D":"IPsec IKE is the key exchange protocol for IPsec, not TLS."}},
  {"id":42,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"Which certificate type requires the most rigorous identity verification and displays organization details in the browser?","options":{"A":"Domain Validation (DV)","B":"Organization Validation (OV)","C":"Extended Validation (EV)","D":"Wildcard"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Extended Validation (EV) certificates require the CA to verify the legal identity, physical existence, and operational status of the organization — the most rigorous vetting process.","A":"DV certificates only verify domain ownership, with minimal identity checks.","B":"OV certificates verify the organization's existence but with less rigor than EV.","C":"Correct. EV certificates require the most thorough identity verification.","D":"Wildcard certificates cover subdomains but are a scope type, not a validation level."}},
  {"id":43,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"During which phase of the identity lifecycle is a user account typically disabled rather than deleted to preserve audit logs?","options":{"A":"Provisioning","B":"Modification","C":"Deprovisioning","D":"Review"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"During deprovisioning (offboarding), accounts are often disabled rather than immediately deleted to preserve audit trail data and allow investigation if needed, then eventually deleted per retention policy.","A":"Provisioning is the creation and setup of a new account.","B":"Modification involves changing existing account attributes or permissions.","C":"Correct. Deprovisioning involves disabling (and eventually deleting) accounts while preserving audit records.","D":"Review involves periodic access reviews (recertification), not account termination."}},
  {"id":44,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"Which concept describes implementing multiple layers of security controls so that if one fails, others still protect the asset?","options":{"A":"Zero trust","B":"Least privilege","C":"Defense in depth","D":"Separation of duties"},"correct_answer":"C","difficulty":1,"explanations":{"correct":"Defense in depth (also called layered security) employs multiple overlapping security controls so that no single failure exposes the asset.","A":"Zero trust eliminates implicit trust and verifies every access request, but is not specifically about layering controls.","B":"Least privilege limits access to the minimum required — not about layering controls.","C":"Correct. Defense in depth uses multiple layers of controls so that failure of one does not compromise overall security.","D":"Separation of duties divides tasks, not security control layers."}},
  {"id":45,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"A company wants to ensure the confidentiality of data transmitted between two offices. Which technology should be used?","options":{"A":"Digital signature","B":"Hashing","C":"VPN with encryption","D":"PKI certificate only"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"A VPN with encryption creates a secure, encrypted tunnel between two sites, ensuring confidentiality of data in transit.","A":"Digital signatures provide integrity and non-repudiation, not confidentiality.","B":"Hashing ensures integrity but does not encrypt or provide confidentiality.","C":"Correct. A VPN with encryption protects the confidentiality of data transmitted between offices.","D":"A PKI certificate alone does not encrypt data; it must be used with a protocol like TLS or VPN."}},
  {"id":46,"domain":1,"subdomain":"1.1","objective":"Compare and contrast various types of security controls","stem":"An organization deploys a system that blocks suspicious traffic before it reaches the target. This is BEST classified as which control type?","options":{"A":"Detective","B":"Corrective","C":"Preventive","D":"Compensating"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Preventive controls stop security incidents from occurring. Blocking suspicious traffic before it reaches its target prevents the attack.","A":"Detective controls identify incidents after they begin; blocking before impact is preventive.","B":"Corrective controls restore systems after an incident.","C":"Correct. Blocking traffic before it causes harm is a preventive control.","D":"Compensating controls are alternatives to primary controls, not the primary blocking mechanism."}},
  {"id":47,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"Which asymmetric algorithm is based on the difficulty of factoring large prime numbers?","options":{"A":"ECC","B":"Diffie-Hellman","C":"RSA","D":"AES"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"RSA security is based on the computational difficulty of factoring the product of two large prime numbers. Breaking RSA requires factoring a large semiprime.","A":"ECC is based on the algebraic structure of elliptic curves over finite fields, not prime factoring.","B":"Diffie-Hellman is based on the discrete logarithm problem, not prime factoring.","C":"Correct. RSA relies on the difficulty of factoring large semiprimes.","D":"AES is a symmetric algorithm and is not based on prime factoring."}},
  {"id":48,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"An employee is granted read access to a database they don't need for their job. Which principle has been violated?","options":{"A":"Separation of duties","B":"Least privilege","C":"Non-repudiation","D":"Defense in depth"},"correct_answer":"B","difficulty":1,"explanations":{"correct":"The principle of least privilege states that users should only have access to what is necessary for their job. Granting unnecessary read access violates this principle.","A":"Separation of duties requires dividing tasks, not directly about access rights.","B":"Correct. Granting access beyond job requirements violates least privilege.","C":"Non-repudiation prevents denial of actions; not related to excessive access.","D":"Defense in depth concerns layering controls, not individual access decisions."}},
  {"id":49,"domain":1,"subdomain":"1.3","objective":"Explain the importance of change management processes","stem":"Which change type requires immediate implementation without going through the standard approval process due to a critical outage?","options":{"A":"Standard change","B":"Normal change","C":"Emergency change","D":"Minor change"},"correct_answer":"C","difficulty":2,"explanations":{"correct":"Emergency changes are implemented outside the normal process when a critical situation requires immediate action. They are documented after the fact and reviewed later.","A":"Standard changes are pre-approved, recurring, low-risk changes.","B":"Normal changes follow the full change management workflow with CAB review.","C":"Correct. Emergency changes bypass normal approval due to urgency but are documented afterward.","D":"Minor change is not a standard ITIL change classification."}},
  {"id":50,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"Which key is used to sign a digital certificate to create a chain of trust?","options":{"A":"The subject's public key","B":"The CA's private key","C":"The subject's private key","D":"The CA's public key"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"When a CA issues a certificate, it signs it using the CA's private key. Recipients verify the signature using the CA's public key, establishing the chain of trust.","A":"The subject's public key is embedded in the certificate but does not sign it.","B":"Correct. The CA's private key signs the certificate, creating the trusted binding.","C":"The subject's private key is kept secret and used for signing documents/authentication, not for the certificate itself.","D":"The CA's public key is used to verify the certificate signature, not to create it."}},
  {"id":51,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"A hashing function that produces the same hash output for two different inputs has which vulnerability?","options":{"A":"Preimage attack","B":"Birthday attack","C":"Collision","D":"Replay attack"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"A collision occurs when two different inputs produce the same hash output. This is a fundamental vulnerability in weak hashing algorithms like MD5 and SHA-1.","A":"A preimage attack finds an input that produces a specific hash value — different from two inputs sharing the same hash.","B":"A birthday attack is the method used to find collisions; the vulnerability itself is called a collision.","C":"Correct. When two different inputs produce the same hash, it is called a collision.","D":"A replay attack reuses captured authentication credentials, unrelated to hashing collisions."}},
  {"id":52,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"Which access control model dynamically grants or denies access based on attributes such as user role, location, time of day, and resource sensitivity?","options":{"A":"MAC","B":"DAC","C":"RBAC","D":"ABAC"},"correct_answer":"D","difficulty":3,"explanations":{"correct":"Attribute-Based Access Control (ABAC) evaluates multiple attributes (user, resource, environment) simultaneously to make fine-grained access control decisions.","A":"MAC uses fixed security labels, not dynamic attribute combinations.","B":"DAC allows owners to set permissions at their discretion without dynamic attribute evaluation.","C":"RBAC assigns permissions based on roles, not dynamic multi-attribute policies.","D":"Correct. ABAC uses combinations of attributes to make dynamic access decisions."}},
  {"id":53,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"Which concept states that a system should fail in a secure state, such as blocking all access when a firewall crashes?","options":{"A":"Fail open","B":"Defense in depth","C":"Fail secure (fail closed)","D":"Least functionality"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"Fail secure (fail closed) means that when a system fails, it defaults to a secure/restrictive state, blocking access rather than allowing unrestricted access.","A":"Fail open means a system allows all traffic when it fails — this is the opposite of secure.","B":"Defense in depth layers controls but doesn't describe failure behavior.","C":"Correct. Fail secure means the system denies access when it fails, maintaining security.","D":"Least functionality means configuring systems with only necessary features enabled, not about failure states."}},
  {"id":54,"domain":1,"subdomain":"1.1","objective":"Compare and contrast various types of security controls","stem":"Which security control type is an incident response plan?","options":{"A":"Technical — corrective","B":"Managerial — operational","C":"Physical — directive","D":"Operational — corrective"},"correct_answer":"D","difficulty":3,"explanations":{"correct":"An incident response plan is an operational control (it involves procedures carried out by people) and is corrective (it guides recovery from security incidents).","A":"Technical controls use technology, not documented procedures.","B":"Managerial controls relate to governance and administration; the IRP itself is operational.","C":"Physical controls protect physical assets; the IRP is a procedural document.","D":"Correct. The IRP is an operational control (people follow procedures) that is corrective (it responds to/corrects incidents)."}},
  {"id":55,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"Which supply chain security concept involves validating the integrity of software components by tracking all components and their sources?","options":{"A":"Code signing","B":"Software Bill of Materials (SBOM)","C":"Static code analysis","D":"Fuzz testing"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"A Software Bill of Materials (SBOM) is a comprehensive list of all components, libraries, and dependencies in a software product, enabling organizations to identify vulnerabilities and track supply chain risks.","A":"Code signing verifies software authenticity with a digital signature but doesn't list components.","B":"Correct. An SBOM inventories all software components and their origins for supply chain transparency.","C":"Static code analysis reviews source code for vulnerabilities but doesn't track all external components.","D":"Fuzz testing sends random inputs to find bugs; it doesn't map component origins."}},
  {"id":56,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"Which concept allows computations to be performed on encrypted data without decrypting it first?","options":{"A":"Quantum key distribution","B":"Homomorphic encryption","C":"Tokenization","D":"Steganography"},"correct_answer":"B","difficulty":5,"explanations":{"correct":"Homomorphic encryption allows mathematical operations to be performed on ciphertext, producing an encrypted result that, when decrypted, matches the result of the same operations on plaintext.","A":"QKD uses quantum mechanics to distribute encryption keys securely; it does not allow computation on encrypted data.","B":"Correct. Homomorphic encryption enables processing of encrypted data without decryption.","C":"Tokenization replaces data with tokens; it does not enable computation on the protected data.","D":"Steganography hides data within another file; it does not enable computation on encrypted data."}},
  {"id":57,"domain":1,"subdomain":"1.3","objective":"Explain the importance of change management processes","stem":"An administrator updates software on a production server. After the update, several services fail. The FIRST step should be:","options":{"A":"Contact the vendor for support","B":"Execute the rollback plan","C":"Document the failure and submit a new change request","D":"Rebuild the server from scratch"},"correct_answer":"B","difficulty":2,"explanations":{"correct":"When a change causes service failures, the immediate action is to execute the pre-approved rollback plan to restore the previous state quickly.","A":"Contacting the vendor may be needed eventually but the immediate priority is service restoration.","B":"Correct. The rollback plan should be executed immediately to restore normal operations.","C":"Documentation and new change requests come after service is restored.","D":"Rebuilding from scratch is a last resort and is far more disruptive than a planned rollback."}},
  {"id":58,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"Which key exchange algorithm is based on the discrete logarithm problem and enables two parties to agree on a shared secret over an insecure channel?","options":{"A":"RSA","B":"AES","C":"Diffie-Hellman","D":"SHA-256"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"The Diffie-Hellman protocol allows two parties to establish a shared secret over a public channel without transmitting the secret itself, based on the computational difficulty of the discrete logarithm problem.","A":"RSA can encrypt a shared secret for exchange but is not based on the same mathematical problem as Diffie-Hellman.","B":"AES is a symmetric encryption algorithm, not a key exchange protocol.","C":"Correct. Diffie-Hellman key exchange uses the discrete logarithm problem to establish a shared secret.","D":"SHA-256 is a hashing algorithm, not a key exchange mechanism."}},
  {"id":59,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"A developer implements key stretching using PBKDF2. What is the PRIMARY purpose of key stretching?","options":{"A":"Increase the length of the encryption key","B":"Make brute-force attacks computationally expensive by adding work factor","C":"Convert symmetric keys to asymmetric keys","D":"Enable keys to be shared across multiple systems"},"correct_answer":"B","difficulty":4,"explanations":{"correct":"Key stretching algorithms like PBKDF2, bcrypt, and Argon2 apply the hashing function many thousands of times, making each password guess computationally expensive and slowing brute-force attacks.","A":"Key stretching increases the computational effort, not necessarily the key length.","B":"Correct. Key stretching makes brute-force and dictionary attacks impractical by requiring significant computation per guess.","C":"Key stretching does not convert between symmetric and asymmetric key types.","D":"Key stretching is applied to individual passwords/keys; it does not facilitate sharing."}},
  {"id":60,"domain":1,"subdomain":"1.1","objective":"Compare and contrast various types of security controls","stem":"A policy requiring that all employees wear ID badges is BEST classified as which type of control?","options":{"A":"Technical — preventive","B":"Physical — deterrent","C":"Operational — directive","D":"Managerial — corrective"},"correct_answer":"C","difficulty":3,"explanations":{"correct":"A policy requiring badge wearing is an operational control (it governs human behavior through a rule) and is directive (it directs or instructs employees on required behavior).","A":"Technical controls use technology, not policies.","B":"Physical controls involve tangible barriers or devices; a policy is not physical.","C":"Correct. A badge policy is an operational directive control — it directs required behavior.","D":"Managerial controls deal with risk management governance; a badge policy is an operational directive."}},
  {"id":61,"domain":1,"subdomain":"1.4","objective":"Explain the importance of using appropriate cryptographic solutions","stem":"Which algorithm provides both encryption and authentication of data, making it an Authenticated Encryption with Associated Data (AEAD) cipher?","options":{"A":"AES-ECB","B":"AES-CBC","C":"AES-GCM","D":"3DES-CBC"},"correct_answer":"C","difficulty":4,"explanations":{"correct":"AES-GCM (Galois/Counter Mode) provides authenticated encryption, ensuring both data confidentiality (encryption) and integrity/authenticity (via GHASH authentication tag) in a single operation.","A":"AES-ECB provides encryption only and is considered insecure due to pattern preservation.","B":"AES-CBC provides encryption but requires a separate HMAC for authentication.","C":"Correct. AES-GCM is an AEAD cipher providing encryption and authentication together.","D":"3DES-CBC is deprecated and provides encryption only, not authentication."}},
  {"id":62,"domain":1,"subdomain":"1.2","objective":"Summarize fundamental security concepts","stem":"Which concept restricts users to accessing only the information relevant to their current task, even if they have a higher clearance level?","options":{"A":"Least privilege","B":"Need-to-know","C":"Separation of duties","D":"Mandatory access control"},"correct_answer":"B","difficulty":3,"explanations":{"correct":"Need-to-know ensures that even cleared individuals only access information directly relevant to their current assignment, limiting exposure beyond what their job requires.","A":"Least privilege limits access rights to the minimum necessary for a job role; need-to-know further restricts within that role.","B":"Correct. Need-to-know ensures access is granted based on task relevance, not just clearance level.","C":"Separation of duties divides critical tasks, not information access by relevance.","D":"MAC enforces access via security labels; need-to-know applies within any access model."}},
]
